// Получаем дату из query параметра (если есть)
const queryDate = $('Webhook').first().json.query?.date;

// Фильтруем события с временем
let events = items.map(item => item.json).filter(e => e.start && e.start.dateTime);

// Если передана дата в query - фильтруем только события этой даты
if (queryDate) {
  events = events.filter(e => {
    const eventDate = new Date(e.start.dateTime);
    // Форматируем дату события в YYYY-MM-DD (в локальном времени события)
    const eventDateStr = e.start.dateTime.split('T')[0];
    return eventDateStr === queryDate;
  });
}

// Считаем события на сегодня для статистики
const today = new Date();
const todayStr = today.toISOString().split('T')[0];
const allEvents = items.map(item => item.json).filter(e => e.start && e.start.dateTime);
const todayEvents = allEvents.filter(e => e.start.dateTime.split('T')[0] === todayStr);

const stats = {
  today: todayEvents.length,
  conversion: 68,
  sum: "2.4M"
};

const meetings = events.map(e => {
  // Парсим время из ISO строки (учитывая часовой пояс события)
  const dateTimeStr = e.start.dateTime;
  const timePart = dateTimeStr.split('T')[1];
  const hours = timePart.substring(0, 2);
  const minutes = timePart.substring(3, 5);
  const time = parseInt(hours) + ':' + minutes;

  return {
    time: time,
    rawTime: e.start.dateTime,
    date: dateTimeStr.split('T')[0],
    client: e.summary || 'Без названия',
    desc: e.description || 'Нет описания',
    status: 'confirmed'
  };
});

return [
  {
    json: {
      stats,
      meetings,
      requestedDate: queryDate || 'all'
    }
  }
];
